// Manager nabíjení auta v25.1 — ZápNak: necykluj OFF→ON při běžícím nabíjení — [1]stop [2]slunce [3]síť [4]rychle_off (priorita #1)
function gS(id){return(global.get("homeassistant.homeAssistant.states['"+id+"']")||{}).state;}
function gB(id){return gS(id)==="on";}
function gF(id,d){var v=parseFloat(gS(id));return isNaN(v)?(d||0):v;}
var cfg=global.get("fve_config")||{};
var hlad=gB("input_boolean.auto_ma_hlad"),auto=gB("input_boolean.automatizovat_nabijeni_auta");
// 2cars: hlad = OR obou chargeru (auto v garazi NEBO venku spusti nabijeni)
function _hSt(id){var s=parseInt(gS(id),10);return s===1||s===2||s===6;}
hlad=hlad||_hSt("sensor.charger_state_garage")||_hSt("sensor.stav_wallboxu_venek");
var solRez=gB("input_boolean.solarni_rezim_nabijeni_auta"),letni=gB("input_boolean.letni_rezim");
var solCyklus=gB("input_boolean.nastavuj_amperaci_chargeru_solar");
var chSt=gS("sensor.charger_state_garage")||"0";
var src=(cfg.solar_forecast_source||"VICTRON").toUpperCase();
var eD=src==="OPEN_METEO"?"sensor.energy_production_today_3":"input_number.predpoved_solarni_vyroby_dnes";
var eZ=src==="OPEN_METEO"?"sensor.energy_production_tomorrow_3":"input_number.predpoved_solarni_vyroby_zitra";
var vD=gF(eD,0),vZ=gF(eZ,0),soc=gF("sensor.battery_percent",0),roz=gF("sensor.rozdil_vyroby_a_spotreby",0);
var FK=cfg.nabijeni_auta_forecast_kwh||40,MS=cfg.nabijeni_auta_solar_w||4000,MSS=cfg.nabijeni_auta_min_soc_slunce||85;
function stop(t){global.set("balancing_solar_car",false);node.status({fill:"grey",shape:"ring",text:t});return[[msg],null,null,null];}
function slunce(t,c){global.set("balancing_solar_car",!!c);node.status({fill:"green",shape:"dot",text:t});return[null,[msg],null,null];}
if(!auto){node.status({fill:"grey",shape:"ring",text:"Auto OFF\u2192NIC"});return null;}
if(!hlad)return stop("Nemá hlad");
// === RYCHLE NABIJENI v25.0 — priorita #1 (override vsech gate) ===
var _rychle = gB("input_boolean.chci_rychle_nabit_auto");
var _rychleTs = flow.get("rychle_start_ts") || 0;
if (_rychle) {
  if (!_rychleTs) { _rychleTs = Date.now(); flow.set("rychle_start_ts", _rychleTs); }
  var _rychleH = cfg.rychle_nabit_deadline_h || 6;
  var _elaMin = (Date.now() - _rychleTs) / 60000;
  // Watchdog: deadline 6h NEBO auto fyzicky plne (chSt=3) -> turn off boolean
  if (_elaMin > _rychleH * 60 || chSt === "3") {
    flow.set("rychle_start_ts", 0);
    msg.payload = {entity_id: "input_boolean.chci_rychle_nabit_auto"};
    var _why = chSt === "3" ? "plne" : ("6h elapsed " + Math.round(_elaMin) + "m");
    node.status({fill:"yellow",shape:"dot",text:"\uD83D\uDE80END " + _why + " SOC:"+soc+"%"});
    return [null,null,null,[msg]];
  }
  // Routing: solar pokud >1500W vyroba & >1000W prebytek; jinak sit MAX
  var _solR = gF("sensor.vyroba_fve",0);
  if (_solR > 1500 && roz > 1000) {
    global.set("balancing_solar_car", false);
    node.status({fill:"green",shape:"dot",text:"\uD83D\uDE80\u2600 sol:"+Math.round(_solR)+"W preb:"+Math.round(roz)+"W "+Math.round(_elaMin)+"m"});
    return [null,[msg],null,null];
  }
  global.set("balancing_solar_car", false);
  node.status({fill:"red",shape:"dot",text:"\uD83D\uDE80\u26A1SIT "+Math.round(_elaMin)+"m SOC:"+soc+"%"});
  return [null,null,[msg],null];
}
// (rychle off): pokud byl ts set, vyresetuj
if (_rychleTs) flow.set("rychle_start_ts", 0);
// §4.10 ZN5+ZN6: záporná nákupní cena — early bypass přes SOC/balancing/last-solar/sell-price gate
var _fpaZ=(global.get("homeassistant.homeAssistant.states['sensor.fve_plan']")||{}).attributes||{};
var _mLiveZ=global.get("fve_current_mode")||"";
var _mPlanZ=_fpaZ.current_mode||"";
if(_mLiveZ==="zaporna_nakupni_cena"||_mPlanZ==="zaporna_nakupni_cena"){
  global.set("balancing_solar_car",false);
  var _gridZn=gB("input_boolean.nastavuj_amperaci_chargeru_grid");
  if(_gridZn&&(chSt==="1"||chSt==="2")){
    node.status({fill:"red",shape:"dot",text:"\uD83D\uDCB0Z\u00e1pNak S\u00cd\u0164 b\u011b\u017e\u00ed ch:"+chSt});
    return null;
  }
  node.status({fill:"red",shape:"dot",text:"\uD83D\uDCB0Z\u00e1pNak\u2192S\u00cd\u0164 MAX SOC:"+soc+"%"});
  return[null,null,[msg],null];
}
// Balancování
var fpa=(global.get("homeassistant.homeAssistant.states['sensor.fve_plan']")||{}).attributes||{};
var bal=fpa.current_mode==="Balancování";
if(!bal&&global.get("balancing_active"))global.set("balancing_active",false);
if(bal){if(soc<99)return stop("⚡Bal SOC:"+soc+"%");
if(solCyklus)return slunce("⚡☀Bal+cyklus SOC:"+soc+"%",true);
var BR=cfg.balancing_grid_reserve_w||1000,BMS=6*3*230+BR;
if(roz>BMS)return slunce("⚡☀Bal+start přeb:"+Math.round(roz)+"W",true);
return stop("⚡Bal žádný přebytek");}
global.set("balancing_solar_car",false);
if(soc<MSS)return stop("SOC "+soc+"%<"+MSS+"%");
// Pravidlo poslednich solarnich hodin: baterie na 100% ma prednost pred autem
var _fpa2=(global.get("homeassistant.homeAssistant.states['sensor.fve_plan_data']")||{}).attributes||{};
var _plan2=_fpa2.plan||[];var _lastSolH2=-1;for(var si2=0;si2<_plan2.length;si2++){if(_plan2[si2].isSolarHour)_lastSolH2=_plan2[si2].hour;}
var _curHr2=new Date().getHours();var _hToLastSol2=_lastSolH2>=0?(_lastSolH2-_curHr2):99;
var LAST_SOL_HRS=cfg.posledni_solarni_hodiny||2;
var _zbSolar2=gF("sensor.energy_production_today_remaining_3",0)*1000;
var _patLastKwh2=(cfg.topeni_patron_last_sol_min_kwh||4)*1000;
var _isSol2=_curHr2>=(cfg.solarni_hodina_od||6)&&_curHr2<(cfg.solarni_hodina_do||20);
var _cantExport2=_isSol2&&(gF("sensor.current_spot_sell_price",1)<=0);
if(_isSol2&&_hToLastSol2<LAST_SOL_HRS&&_zbSolar2<_patLastKwh2&&!_cantExport2)return stop("☀Posl."+LAST_SOL_HRS+"h sol→bat100% zbSol:"+Math.round(_zbSolar2)+"W");
// §4.6+§5.1: zakaz pretoku + SOC >= drain prah → spust solar nabijeni (energie nema kam jit)
var _fveMode=(fpa.current_mode||"");
var _DRAIN_AUTO=cfg.nabijeni_auta_soc_drain_prah||95;
var _zakazPretoku=_fveMode==="zakaz_pretoku";
var _solW=gF("sensor.vyroba_fve",0);
var _gridW=gF("sensor.spotreba_ze_site",0);
var _ultraLevna=global.get("ultra_levna_energie")||false;
var _zakazOk=_zakazPretoku&&soc>=_DRAIN_AUTO&&_solW>1000&&!solCyklus&&(_gridW<(cfg.nabijeni_auta_max_grid_w||200)||_ultraLevna);
if(_zakazOk)return slunce("☀Zákaz přetoků SOC:"+soc+"%→solar sol:"+Math.round(_solW)+"W grid:"+Math.round(_gridW)+"W",false);
// §5.1 SELL-PRICE GUARD analogicky korekční smyčce: pokud sell > max a NENI zakaz_pretoku/zaporna,
// NESPOUŠTĚJ solar — korekce by ho stejně okamžitě vypnula → cycling ON/OFF (problemy.txt 7.5.2026).
// Vyjimka pro _zakazOk vyse je OK: pri zakazu pretoku sell<=0 takze sellPrice<=spMax automaticky.
var _spS_mgr=global.get("homeassistant.homeAssistant.states['input_number.aktualni_cena_prodej_kwh_q']")||{};
var _sp_mgr=parseFloat(_spS_mgr.state);if(isNaN(_sp_mgr))_sp_mgr=0;
var _spMax_mgr=cfg.nabijeni_auta_max_sell_price;if(_spMax_mgr==null)_spMax_mgr=1.0;
var _cantExp_mgr=(_fveMode==="zakaz_pretoku")||(_sp_mgr<=0);
if(!_cantExp_mgr&&_sp_mgr>_spMax_mgr){return stop("☀OFF sell:"+_sp_mgr.toFixed(2)+">"+_spMax_mgr+"Kč (§5.1)");}
// §4.10.2 bod 3: záporná nákupní cena → nabíjet auto ze SÍTĚ na max ampéráži
var _zapNak=_fveMode==="zaporna_nakupni_cena";
if(_zapNak){node.status({fill:"red",shape:"dot",text:"ZápNak→SÍŤ sol:"+Math.round(_solW)+"W"});return[null,null,[msg],null];}
if(solCyklus){node.status({fill:"green",shape:"dot",text:"☀Cyklus SOC:"+soc+"% přeb:"+Math.round(roz)+"W ch:"+chSt});return[null,[msg],null,null];}
var curSol=gF("sensor.vyroba_fve",0),chActive=chSt==="2";
if(chActive&&curSol>MS&&!solCyklus)return slunce("☀Takeover sol:"+Math.round(curSol)+"W",false);
var bSD=global.get("balancing_solar_dump")||false;
if(bSD&&curSol>MS)return slunce("⚡SolDump sol:"+Math.round(curSol)+"W",false);
var avail=gF("sensor.fve_dostupny_prebytek",0),maPreb=roz>MS;
if(solRez&&maPreb){node.status({fill:"green",shape:"dot",text:"Solar ON přeb:"+Math.round(roz)+"W"});return[null,[msg],null,null];}
if(letni&&maPreb){node.status({fill:"green",shape:"dot",text:"Letní přeb:"+Math.round(roz)+"W"});return[null,[msg],null,null];}
if(vD>FK&&maPreb){node.status({fill:"green",shape:"dot",text:"Dnes "+Math.round(vD)+"kWh+přeb"});return[null,[msg],null,null];}
if(vZ>FK&&maPreb){node.status({fill:"green",shape:"dot",text:"Zítra "+Math.round(vZ)+"kWh+přeb"});return[null,[msg],null,null];}
if(vZ>FK||vD>FK){node.status({fill:"orange",shape:"ring",text:"Čeká přeb dnes:"+Math.round(vD)+" zítra:"+Math.round(vZ)});return[[msg],null,null,null];}
node.status({fill:"blue",shape:"dot",text:"Síť dnes:"+Math.round(vD)+" zítra:"+Math.round(vZ)+" soc:"+soc+"%"});
return[null,null,[msg],null];

// Auto Hunger Probe — zjištění skutečného stavu auta při připojení
// Řeší: state 6 (WaitStart) nerozlišuje nabité vs hladové auto
// Trigger: state change z obou wallboxů
// Outputs: [1] start probe | [2] hlad ON | [3] hlad OFF

var entityId = msg.topic || "";
var isGarage = entityId === "sensor.charger_state_garage";
var newState = parseInt(msg.payload) || 0;
var oldState = (msg.data && msg.data.old_state) ? parseInt(msg.data.old_state.state) || 0 : 0;

if (isGarage) {
    // === GARÁŽ — probe při prvním připojení ===
    if (newState === 0) {
        // Odpojeno → žádný hlad
        flow.set("probe_active", false);
        flow.set("garage_hunger", false);
        node.status({fill: "grey", shape: "ring", text: "Garáž: odpojeno"});
    }
    else if (newState === 3) {
        // Nabité → žádný hlad
        flow.set("probe_active", false);
        flow.set("garage_hunger", false);
        node.status({fill: "green", shape: "dot", text: "Garáž: nabité"});
    }
    else if (newState === 2) {
        // Nabíjí se → má hlad
        flow.set("garage_hunger", true);
        node.status({fill: "blue", shape: "dot", text: "Garáž: nabíjí se"});
    }
    else if (newState === 6) {
        // WaitStart: wallbox OFF, auto may still be hungry
        var wasProbed = flow.get("garage_probed") || false;
        if (!wasProbed) {
            flow.set("probe_active", true);
            flow.set("garage_hunger", true);
            node.status({fill: "yellow", shape: "dot", text: "Probe (st.6)..."});
            return [msg, msg, null];
        } else {
            node.status({fill: "orange", shape: "ring", text: "WaitStart hlad=" + (flow.get("garage_hunger") ? "ON" : "OFF")});
        }
    }
    else if (oldState === 0 && newState !== 0) {
        // Auto právě připojeno → spustit probe
        flow.set("probe_active", true);
        flow.set("garage_probed", false);
        flow.set("garage_hunger", true); // bezpečný default
        node.status({fill: "yellow", shape: "dot", text: "Garáž: probe spuštěn..."});
        // Out1: start probe sekvenci, Out2: hlad ON (safe default)
        return [msg, msg, null];
    }
} else {
    // === VENKOVNÍ WALLBOX — bez probe (zachováno staré chování) ===
    if (newState === 0 || newState === 3) {
        flow.set("outdoor_hunger", false);
    } else if (newState === 2 || newState === 4 || newState === 6) {
        flow.set("outdoor_hunger", true);
    }
}

// Vyhodnoť kombinovaný hlad (garáž OR venkovní)
var garageHunger = flow.get("garage_hunger") || false;
var outdoorHunger = flow.get("outdoor_hunger") || false;

if (garageHunger || outdoorHunger) {
    return [null, msg, null]; // Out2: hlad ON
} else {
    return [null, null, msg]; // Out3: hlad OFF
}

// Probe Read Result — čtení stavu chargeru po 20s delay
// Outputs: [1] hlad ON | [2] hlad OFF | [3] charger OFF (vždy po probe)

// Kontrola, zda probe nebyl mezitím zrušen (např. auto odpojeno)
if (!flow.get("probe_active")) {
    node.status({fill: "grey", shape: "ring", text: "Probe zrušen"});
    return [null, null, msg]; // jen vypni charger pro jistotu
}
flow.set("probe_active", false);
flow.set("garage_probed", true);

var chargerState = parseInt(
    (global.get("homeassistant.homeAssistant.states['sensor.charger_state_garage']") || {}).state
) || 0;

var outdoorHunger = flow.get("outdoor_hunger") || false;

if (chargerState === 3) {
    // Auto je nabité → garage nemá hlad
    flow.set("garage_hunger", false);
    node.status({fill: "green", shape: "dot", text: "Probe: nabité (st.3)"});
    if (outdoorHunger) {
        return [msg, null, msg]; // venkovní má hlad → celkově ON
    }
    return [null, msg, msg]; // žádný hlad → OFF
} else {
    // Auto má hlad (st.2) nebo jiný stav
    flow.set("garage_hunger", true);
    node.status({fill: "red", shape: "dot", text: "Probe: hlad (st." + chargerState + ")"});
    return [msg, null, msg]; // hlad ON + charger OFF
}

// SPLITTER 2 WALLBOXY (sdileny apply) — branch 2cars (user 17.6.2026)
// Vstup: msg.payload = TOTAL amp budget B; msg.src = "sit"|"solar".
// Deli mezi garaz/venek (hlad=stav{1,2,6}); per-charger cap zn_auto_max_amps (arbitr peak).
function gS(id){return (global.get("homeassistant.homeAssistant.states['"+id+"']")||{}).state;}
function wants(s){var v=parseInt(s,10);return v===1||v===2||v===6;}
var B=parseInt(msg.payload,10); if(isNaN(B)||B<0)B=0;
var MAXA=16,MINA=6;
var gW=wants(gS("sensor.charger_state_garage"));
var oW=wants(gS("sensor.stav_wallboxu_venek"));
var znCap=global.get("zn_auto_max_amps");
function clampOff(a){a=Math.floor(a);if(znCap!=null)a=Math.min(a,znCap);if(a<MINA)return 0;return Math.min(a,MAXA);}
var gA=0,oA=0;
if(gW&&oW){
  if(B>=2*MINA){var half=Math.floor(B/2);var ex=B-2*half;gA=clampOff(half+ex);oA=clampOff(half);}
  else{gA=clampOff(B);oA=0;}
}else if(gW){gA=clampOff(B);}
else if(oW){oA=clampOff(B);}
var any=(gA>=MINA)||(oA>=MINA);
var src=msg.src||"sit";
var gAmp=gA>=MINA?{payload:gA}:null;
var gSw={payload:gA>=MINA?"on":"off"};
var oAmp=oA>=MINA?{payload:oA}:null;
var oSw={payload:oA>=MINA?"on":"off"};
var boolM=any?null:{src:src};
node.status({fill:any?"green":"grey",shape:"dot",text:"B"+B+" G:"+(gW?gA+"A":"-")+" V:"+(oW?oA+"A":"-")+(znCap!=null?" cap"+znCap:"")+(any?"":" STOP")});
return [gAmp,gSw,oAmp,oSw,boolM];
